  1	import * as React from 'react';
  2	import {
  3	  getName,
  4	  ModalBody,
  5	  ModalFooter,
  6	  ModalTitle,
  7	  StorageConsumerKind,
  8	  useCustomTranslation,
  9	  StorageConsumerModel,
 10	  getAnnotations,
 11	} from '@odf/shared';
 12	import { CommonModalProps } from '@odf/shared/modals';
 13	import {
 14	  k8sDelete,
 15	  k8sPatch,
 16	  YellowExclamationTriangleIcon,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import * as _ from 'lodash-es';
 19	import { Trans } from 'react-i18next';
 20	import {
 21	  Button,
 22	  Checkbox,
 23	  Flex,
 24	  FlexItem,
 25	  FormGroup,
 26	  Modal,
 27	  ModalVariant,
 28	} from '@patternfly/react-core';
 29	
 30	type RemoveClientModalProps = CommonModalProps<{
 31	  resource: StorageConsumerKind;
 32	}>;
 33	
 34	const ANNOTATIONS_PATH = '/metadata/annotations';
 35	const FORCE_DELETION_ANNOTATION = 'ocs.openshift.io/force-deletion';
 36	
 37	const RemoveClientModal: React.FC<RemoveClientModalProps> = (props) => {
 38	  const {
 39	    extraProps: { resource },
 40	    isOpen,
 41	    closeModal,
 42	  } = props;
 43	  const { t } = useCustomTranslation();
 44	  const [confirmed, setConfirmed] = React.useState(false);
 45	  const [inProgress, setProgress] = React.useState(false);
 46	  const [forceDeletion, setForceDeletion] = React.useState(false);
 47	  const [error, setError] = React.useState<Error>(null);
 48	  const MODAL_TITLE = t('Permanently delete StorageConsumer?');
 49	  const onSubmit = async (event) => {
 50	    event.preventDefault();
 51	    setProgress(true);
 52	    if (forceDeletion) {
 53	      const annotations = getAnnotations(resource);
 54	      const areAnnotationsPresent = !_.isEmpty(annotations);
 55	      const guardedAnnotations = _.isEmpty(annotations) ? {} : annotations;
 56	      const updatedAnnotations = {
 57	        ...guardedAnnotations,
 58	        [FORCE_DELETION_ANNOTATION]: '',
 59	      };
 60	      try {
 61	        await k8sPatch({
 62	          model: StorageConsumerModel,
 63	          resource,
 64	          data: [
 65	            {
 66	              op: areAnnotationsPresent ? 'replace' : 'add',
 67	              path: ANNOTATIONS_PATH,
 68	              value: updatedAnnotations,
 69	            },
 70	          ],
 71	        });
 72	      } catch (err) {
 73	        setError(err);
 74	        setProgress(false);
 75	        return;
 76	      }
 77	    }
 78	    k8sDelete({ model: StorageConsumerModel, resource })
 79	      .then(() => {
 80	        setProgress(false);
 81	        closeModal();
 82	      })
 83	      .catch((err) => {
 84	        setProgress(false);
 85	        setError(err);
 86	      });
 87	  };
 88	
 89	  const onKeyUp = (e) => {
 90	    setConfirmed(e.currentTarget.value === getName(resource));
 91	  };
 92	
 93	  return (
 94	    <Modal isOpen={isOpen} onClose={closeModal} variant={ModalVariant.small}>
 95	      <ModalTitle>
 96	        <YellowExclamationTriangleIcon className="co-icon-space-r" />{' '}
 97	        {MODAL_TITLE}
 98	      </ModalTitle>
 99	      <ModalBody>
100	        <p>
101	          <Trans t={t}>
102	            This will remove the StorageConsumer from the environment. This
103	            action cannot be undone.
104	          </Trans>
105	        </p>
106	        <p>
107	          <FormGroup>
108	            <Checkbox
109	              id="force-deletion-checkbox"
110	              label={t('Force deletion')}
111	              isChecked={forceDeletion}
112	              onChange={(_event, checked) => setForceDeletion(checked)}
113	              data-test="force-deletion-checkbox"
114	              description={t(
115	                'Erases all associated data and Ceph/Rook resources. Recommended only if the storage used by this StorageConsumer is no longer needed.'
116	              )}
117	            />
118	          </FormGroup>
119	        </p>
120	        <p>
121	          <Trans t={t}>
122	            Confirm deletion by typing{' '}
123	            <strong className="co-break-word">
124	              {{ name: getName(resource) }}
125	            </strong>{' '}
126	            below:
127	          </Trans>
128	        </p>
129	        <input
130	          type="text"
131	          data-test="project-name-input"
132	          className="pf-v6-c-form-control"
133	          onKeyUp={onKeyUp}
134	          placeholder={t('Enter name')}
135	          aria-label={t('Type client name to confirm {{label}}', {
136	            label: StorageConsumerModel.labelKey,
137	          })}
138	        />
139	      </ModalBody>
140	      <ModalFooter inProgress={inProgress} errorMessage={error?.message}>
141	        <Flex direction={{ default: 'row' }}>
142	          <FlexItem>
143	            <Button
144	              type="submit"
145	              variant="danger"
146	              isDisabled={!confirmed}
147	              data-test="confirm-action"
148	              id="confirm-action"
149	              onClick={onSubmit}
150	            >
151	              {t('Delete')}
152	            </Button>
153	          </FlexItem>
154	          <FlexItem>
155	            <Button
156	              type="button"
157	              variant="secondary"
158	              data-test-id="modal-cancel-action"
159	              onClick={() => closeModal()}
160	              aria-label={t('Cancel')}
161	            >
162	              {t('Cancel')}
163	            </Button>
164	          </FlexItem>
165	        </Flex>
166	      </ModalFooter>
167	    </Modal>
168	  );
169	};
170	
171	export default RemoveClientModal;

